1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEAR_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	const FRAGILE_ENCHANTMENT_THRESHOLD = 8;
12	const FRAGILE_REIMBURSEMENT_RATE = 0.5;
13	
14	const COMPONENT_BLOCK_SIZE = 3;
15	const COMPONENT_BLOCK_PREMIUM = 60;
16	
17	type ItemTypeInfo = {
18	  basePremium: number;
19	  insuranceValue: number;
20	  isComponent: boolean;
21	};
22	
23	const ITEM_REGISTRY: Record<string, ItemTypeInfo> = {
24	  sword: { basePremium: 100, insuranceValue: 1000, isComponent: false },
25	  amulet: { basePremium: 60, insuranceValue: 600, isComponent: false },
26	  staff: { basePremium: 80, insuranceValue: 800, isComponent: false },
27	  potion: { basePremium: 40, insuranceValue: 400, isComponent: false },
28	  rune: { basePremium: 25, insuranceValue: 250, isComponent: true },
29	  moonstone: { basePremium: 25, insuranceValue: 250, isComponent: true },
30	};
31	
32	const isComponent = (type: string): boolean => ITEM_REGISTRY[type].isComponent;
33	
34	const basePremiumFor = (type: string): number => ITEM_REGISTRY[type].basePremium;
35	
36	const insuranceValueFor = (type: string): number =>
37	  ITEM_REGISTRY[type].insuranceValue;
38	
39	type Item = {
40	  type: string;
41	  cursed?: boolean;
42	  enchantment?: number;
43	  material?: string;
44	};
45	type QuoteStep = { op: "quote"; items: Item[] };
46	type Damage = { itemType: string; amount: number };
47	type Incident = { cause: string; damages: Damage[] };
48	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
49	type Step = QuoteStep | ClaimStep;
50	type Customer = { yearsWithMHPCO: number };
51	type Scenario = { customer: Customer; steps: Step[] };
52	
53	type Policy = { items: Item[]; remainingCap: number };
54	
55	const groupedBasePremium = (type: string, count: number): number => {
56	  if (isComponent(type) && count === COMPONENT_BLOCK_SIZE) {
57	    return COMPONENT_BLOCK_PREMIUM;
58	  }
59	  return count * basePremiumFor(type);
60	};
61	
62	const countByType = (items: Item[]): Map<string, number> => {
63	  const counts = new Map<string, number>();
64	  for (const item of items) {
65	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
66	  }
67	  return counts;
68	};
69	
70	const sumBasePremiums = (items: Item[]): number =>
71	  Array.from(countByType(items)).reduce(
72	    (total, [type, count]) => total + groupedBasePremium(type, count),
73	    0,
74	  );
75	
76	const surchargeFor = (item: Item, applies: boolean, rate: number): number =>
77	  applies ? basePremiumFor(item.type) * rate : 0;
78	
79	const isCursed = (item: Item): boolean => item.cursed === true;
80	
81	const isHighlyEnchanted = (item: Item): boolean =>
82	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
83	
84	const itemSurchargeFor = (item: Item): number =>
85	  surchargeFor(item, isCursed(item), CURSE_SURCHARGE_RATE) +
86	  surchargeFor(item, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
87	
88	const sumItemSurcharges = (items: Item[]): number =>
89	  items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
90	
91	const firstInsuranceSurcharge = (basePremium: number): number =>
92	  basePremium * FIRST_INSURANCE_RATE;
93	
94	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
95	  customer.yearsWithMHPCO >= LOYALTY_YEAR_THRESHOLD
96	    ? basePremium * LOYALTY_DISCOUNT_RATE
97	    : 0;
98	
99	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
100	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
101	
102	const quotePremium = (
103	  items: Item[],
104	  customer: Customer,
105	  isFollowUp: boolean,
106	): number => {
107	  const basePremium = sumBasePremiums(items);
108	  const insurancePremium = Math.ceil(
109	    basePremium +
110	      sumItemSurcharges(items) +
111	      firstInsuranceSurcharge(basePremium) -
112	      loyaltyDiscount(basePremium, customer) -
113	      followUpDiscount(basePremium, isFollowUp),
114	  );
115	  return insurancePremium + PROCESSING_FEE;
116	};
117	
118	const insuranceSum = (items: Item[]): number =>
119	  items.reduce((sum, item) => sum + insuranceValueFor(item.type), 0);
120	
121	const isFragile = (item: Item): boolean =>
122	  (item.enchantment ?? 0) >= FRAGILE_ENCHANTMENT_THRESHOLD;
123	
124	const reimbursedAmount = (damage: Damage, item: Item): number =>
125	  isFragile(item) ? damage.amount * FRAGILE_REIMBURSEMENT_RATE : damage.amount;
126	
127	const damagePayout = (damage: Damage, items: Item[]): number => {
128	  const item = items.find((i) => i.type === damage.itemType) as Item;
129	  return reimbursedAmount(damage, item) - DEDUCTIBLE;
130	};
131	
132	const runQuote = (
133	  step: QuoteStep,
134	  customer: Customer,
135	  isFollowUp: boolean,
136	): { result: { premium: number }; policy: Policy } => {
137	  const premium = quotePremium(step.items, customer, isFollowUp);
138	  const policy: Policy = {
139	    items: step.items,
140	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
141	  };
142	  return { result: { premium }, policy };
143	};
144	
145	const runClaim = (
146	  step: ClaimStep,
147	  policies: Policy[],
148	): { result: { payout: number; remainingCap: number }; policy: Policy } => {
149	  const policy = policies[step.policy];
150	  const payout = step.incident.damages.reduce(
151	    (sum, damage) => sum + damagePayout(damage, policy.items),
152	    0,
153	  );
154	  const updatedPolicy: Policy = {
155	    ...policy,
156	    remainingCap: policy.remainingCap - payout,
157	  };
158	  return {
159	    result: { payout, remainingCap: updatedPolicy.remainingCap },
160	    policy: updatedPolicy,
161	  };
162	};
163	
164	const FIRST_STEP_INDEX = 0;
165	
166	export const runScenario = (scenario: Scenario): unknown => {
167	  const policies: Policy[] = [];
168	  const results = scenario.steps.map((step, index) => {
169	    if (step.op === "quote") {
170	      const isFollowUp = index > FIRST_STEP_INDEX;
171	      const { result, policy } = runQuote(step, scenario.customer, isFollowUp);
172	      policies.push(policy);
173	      return result;
174	    }
175	    const { result, policy } = runClaim(step, policies);
176	    policies[step.policy] = policy;
177	    return result;
178	  });
179	  return { results };
180	};
